#ifndef __ARCH_CPU_H__
#define __ARCH_CPU_H__

/**
 * @file cpu.h
 * @brief Architecture-facing CPU identity helper boundary.
 *
 * Shared scheduler and boot code use this helper instead of directly naming
 * the architecture register that stores the current CPU index.
 */

#include "common.h"

#if defined(__loongarch64)

static inline uint64 arch_cpu_id(void)
{
    uint64 id;
    __asm__ volatile("csrrd %0, 0x20" : "=r"(id));
    return id;
}

#else

#include "riscv.h"

static inline uint64 arch_cpu_id(void)
{
    return r_tp();
}

#endif

#endif // __ARCH_CPU_H__

#ifndef __ARCH_MMU_H__
#define __ARCH_MMU_H__

/**
 * @file mmu.h
 * @brief Architecture-facing page-table token and TLB helper boundary.
 */

#include "common.h"

#if defined(__loongarch64)

/* LA uses DMW direct-mapping — no SATP. For initial shared-path bring-up,
 * kernel lives in the direct window and user address space is managed through
 * the LA page table (PGD). Provide stub tokens. */
static inline uint64 arch_mmu_page_token(uint64 pgtbl)
{
    (void)pgtbl;
    return 0;
}

static inline uint64 arch_mmu_current_token(void)
{
    return 0;
}

static inline void arch_mmu_write_token(uint64 token)
{
    (void)token;
}

static inline void arch_mmu_flush_tlb(void)
{
    __asm__ volatile("invtlb 0, $zero, $zero");
}

#else

#include "mem/vmem.h"
#include "riscv.h"

static inline uint64 arch_mmu_page_token(uint64 pgtbl)
{
    return MAKE_SATP(pgtbl);
}

static inline uint64 arch_mmu_current_token(void)
{
    return r_satp();
}

static inline void arch_mmu_write_token(uint64 token)
{
    w_satp(token);
}

static inline void arch_mmu_flush_tlb(void)
{
    sfence_vma();
}

#endif

#endif // __ARCH_MMU_H__

#ifndef __ARCH_TRAPFRAME_H__
#define __ARCH_TRAPFRAME_H__

/**
 * @file trapframe.h
 * @brief Architecture-facing process trapframe accessor boundary.
 *
 * Shared trap and syscall code use these helpers instead of directly naming
 * the architecture register fields inside `trapframe_t`. The default RISC-V
 * implementation preserves the existing struct layout and trampoline offsets;
 * the LoongArch64 build maps the same semantic operations to the saved frame
 * consumed by `la_proc_user_return()`.
 */

#include "common.h"
#include "lib/print.h"
#include "arch/trapframe_types.h"

static inline uint64 arch_tf_user_pc(const trapframe_t *tf)
{
#if defined(__loongarch64)
    return tf->era;
#else
    return tf->epc;
#endif
}

static inline void arch_tf_set_user_pc(trapframe_t *tf, uint64 pc)
{
#if defined(__loongarch64)
    tf->era = pc;
#else
    tf->epc = pc;
#endif
}

static inline uint64 arch_tf_user_sp(const trapframe_t *tf)
{
    return tf->sp;
}

static inline void arch_tf_set_user_sp(trapframe_t *tf, uint64 sp)
{
    tf->sp = sp;
}

static inline void arch_tf_advance_user_pc(trapframe_t *tf, uint64 bytes)
{
#if defined(__loongarch64)
    tf->era += bytes;
#else
    tf->epc += bytes;
#endif
}

static inline uint64 arch_tf_syscall_num(const trapframe_t *tf)
{
    return tf->a7;
}

static inline uint64 arch_tf_arg(const trapframe_t *tf, int n)
{
    switch (n) {
        case 0:
            return tf->a0;
        case 1:
            return tf->a1;
        case 2:
            return tf->a2;
        case 3:
            return tf->a3;
        case 4:
            return tf->a4;
        case 5:
            return tf->a5;
        default:
            panic("arch_tf_arg: illegal arg num");
            return -1;
    }
}

static inline void arch_tf_set_return(trapframe_t *tf, uint64 value)
{
    tf->a0 = value;
}

static inline uint64 arch_tf_return(const trapframe_t *tf)
{
    return tf->a0;
}

static inline void arch_tf_set_user_return_address(trapframe_t *tf, uint64 value)
{
    tf->ra = value;
}

static inline void arch_tf_set_user_tls(trapframe_t *tf, uint64 value)
{
    tf->tp = value;
}

static inline void arch_tf_set_arg(trapframe_t *tf, int n, uint64 value)
{
    switch (n) {
        case 0:
            tf->a0 = value;
            return;
        case 1:
            tf->a1 = value;
            return;
        case 2:
            tf->a2 = value;
            return;
        case 3:
            tf->a3 = value;
            return;
        case 4:
            tf->a4 = value;
            return;
        case 5:
            tf->a5 = value;
            return;
        default:
            panic("arch_tf_set_arg: illegal arg num");
    }
}

static inline void arch_tf_set_kernel_token(trapframe_t *tf, uint64 token)
{
#if defined(__loongarch64)
    tf->kernel_token = token;
    tf->kernel_metadata_valid = 1;
#else
    tf->kernel_satp = token;
#endif
}

static inline uint64 arch_tf_kernel_token(const trapframe_t *tf)
{
#if defined(__loongarch64)
    if (!tf->kernel_metadata_valid)
        panic("arch_tf_kernel_token: missing LA return metadata");
    return tf->kernel_token;
#else
    return tf->kernel_satp;
#endif
}

static inline void arch_tf_set_kernel_stack(trapframe_t *tf, uint64 stack)
{
#if defined(__loongarch64)
    tf->kernel_stack = stack;
    tf->kernel_metadata_valid = 1;
#else
    tf->kernel_sp = stack;
#endif
}

static inline uint64 arch_tf_kernel_stack(const trapframe_t *tf)
{
#if defined(__loongarch64)
    if (!tf->kernel_metadata_valid)
        panic("arch_tf_kernel_stack: missing LA return metadata");
    return tf->kernel_stack;
#else
    return tf->kernel_sp;
#endif
}

static inline void arch_tf_set_kernel_trap(trapframe_t *tf, uint64 handler)
{
#if defined(__loongarch64)
    tf->kernel_trap = handler;
    tf->kernel_metadata_valid = 1;
#else
    tf->kernel_trap = handler;
#endif
}

static inline uint64 arch_tf_kernel_trap(const trapframe_t *tf)
{
#if defined(__loongarch64)
    if (!tf->kernel_metadata_valid)
        panic("arch_tf_kernel_trap: missing LA return metadata");
    return tf->kernel_trap;
#else
    return tf->kernel_trap;
#endif
}

static inline void arch_tf_set_kernel_cpu_id(trapframe_t *tf, uint64 id)
{
#if defined(__loongarch64)
    tf->kernel_cpu_id = id;
    tf->kernel_metadata_valid = 1;
#else
    tf->kernel_hartid = id;
#endif
}

static inline uint64 arch_tf_kernel_cpu_id(const trapframe_t *tf)
{
#if defined(__loongarch64)
    if (!tf->kernel_metadata_valid)
        panic("arch_tf_kernel_cpu_id: missing LA return metadata");
    return tf->kernel_cpu_id;
#else
    return tf->kernel_hartid;
#endif
}

static inline uint64 arch_tf_debug_ra(const trapframe_t *tf)
{
    return tf->ra;
}

static inline uint64 arch_tf_debug_sp(const trapframe_t *tf)
{
    return tf->sp;
}

static inline uint64 arch_tf_debug_tp(const trapframe_t *tf)
{
    return tf->tp;
}

static inline uint64 arch_tf_debug_arg(const trapframe_t *tf, int n)
{
    return arch_tf_arg(tf, n);
}

#endif // __ARCH_TRAPFRAME_H__

#ifndef __ARCH_PROC_H__
#define __ARCH_PROC_H__

/**
 * @file proc.h
 * @brief Architecture-facing process entry and user-return helpers.
 *
 * Shared process code uses this boundary when preparing a scheduler context
 * and returning from the scheduler-owned process path toward user mode. The
 * current implementation preserves the existing RISC-V context layout and
 * trampoline return behavior; a future LoongArch64 shared process path can
 * provide equivalent semantics here without changing `kernel/proc/proc.c`.
 */

#include "common.h"
#include "mem/pmem.h"
#include "mem/vmem.h"
#include "memlayout.h"
#include "arch/trapframe_types.h"
#include "lib/str.h"
#include "trap/trap.h"

struct proc;

typedef struct context {
    uint64 ra; // return address
    uint64 sp; // kernel stack pointer

    // callee-saved registers
    uint64 s0;
    uint64 s1;
    uint64 s2;
    uint64 s3;
    uint64 s4;
    uint64 s5;
    uint64 s6;
    uint64 s7;
    uint64 s8;
#if defined(__loongarch64)
    uint64 fp;
#else
    uint64 s9;
    uint64 s10;
    uint64 s11;
#endif
} context_t;

static inline void arch_proc_context_init(context_t *ctx,
                                          uint64 return_pc,
                                          uint64 kernel_stack_top)
{
    ctx->ra = return_pc;
    ctx->sp = kernel_stack_top;
}

#if defined(__loongarch64)
uint64 la_proc_kstack_base(int id);
void la_proc_prepare_current_return_metadata(struct proc *p, trapframe_t *tf);
void la_proc_user_return(trapframe_t *tf);
#endif

/**
 * @brief Return the architecture-owned kernel stack base for a process slot.
 *
 * @param id Shared process table index.
 * @return Kernel stack base address. `base + PGSIZE` is the initial stack top.
 */
static inline uint64 arch_proc_kstack_base(int id)
{
#if defined(__loongarch64)
    return la_proc_kstack_base(id);
#else
    return KSTACK(id);
#endif
}

static inline uint64 arch_proc_kstack_top(uint64 base)
{
    return base + KSTACK_PAGES * PGSIZE;
}

static inline uint64 arch_proc_mmap_begin(void)
{
    return MMAP_BEGIN;
}

static inline uint64 arch_proc_mmap_pages(void)
{
    return (MMAP_END - MMAP_BEGIN) / PGSIZE;
}

static inline trapframe_t *arch_proc_trapframe_alloc(void)
{
    return (trapframe_t *)pmem_alloc(true);
}

static inline void arch_proc_trapframe_zero(trapframe_t *tf)
{
    memset(tf, 0, PGSIZE);
}

static inline void arch_proc_trapframe_clone(trapframe_t *dst,
                                             const trapframe_t *src)
{
    memmove(dst, src, PGSIZE);
}

static inline void arch_proc_trapframe_init_exec(trapframe_t *dst,
                                                 const trapframe_t *src)
{
#if defined(__loongarch64)
    (void)src;
    arch_proc_trapframe_zero(dst);
#else
    arch_proc_trapframe_clone(dst, src);
#endif
}

static inline int arch_proc_trapframe_map(pgtbl_t pgtbl, trapframe_t *tf)
{
    return vm_mappages(pgtbl, TRAPFRAME, (uint64)tf, PGSIZE, PTE_R | PTE_W);
}

static inline void arch_proc_trapframe_free(trapframe_t *tf)
{
    pmem_free((uint64)tf, true);
}

static inline void arch_proc_prepare_user_return(struct proc *p,
                                                 trapframe_t *tf)
{
#if defined(__loongarch64)
    la_proc_prepare_current_return_metadata(p, tf);
#else
    (void)p;
    (void)tf;
#endif
}

static inline void arch_proc_user_return(trapframe_t *tf)
{
#if defined(__loongarch64)
    la_proc_user_return(tf);
#else
    (void)tf;
    trap_user_return();
#endif
}

#endif // __ARCH_PROC_H__

#ifndef __ARCH_SYSCALL_H__
#define __ARCH_SYSCALL_H__

/**
 * @file syscall.h
 * @brief Architecture-facing syscall register and trap-cause helpers.
 *
 * Shared syscall dispatch uses this boundary for the current process syscall
 * ABI. The RISC-V build preserves the existing environment-call trap code `8`;
 * the LoongArch64 build maps user syscall exceptions to code `0xb` over the
 * same `a7`, `a0`-`a5`, and `a0` return-value semantics.
 */

#include "common.h"
#include "arch/trapframe.h"
#include "proc/cpu.h"

static inline int arch_syscall_is_user_trap(int trap_code)
{
#if defined(__loongarch64)
    return trap_code == 0xb;
#else
    return trap_code == 8;
#endif
}

static inline void arch_syscall_advance_tf_user_pc(trapframe_t *tf)
{
    arch_tf_advance_user_pc(tf, 4);
}

static inline int arch_syscall_tf_number(const trapframe_t *tf)
{
    return (int)arch_tf_syscall_num(tf);
}

static inline uint64 arch_syscall_tf_arg(const trapframe_t *tf, int n)
{
    return arch_tf_arg(tf, n);
}

static inline void arch_syscall_tf_set_return(trapframe_t *tf, uint64 value)
{
    arch_tf_set_return(tf, value);
}

static inline void arch_syscall_advance_user_pc(trapframe_t *tf)
{
    arch_syscall_advance_tf_user_pc(tf);
}

static inline int arch_syscall_current_number(void)
{
    proc_t *p = myproc();

    return arch_syscall_tf_number(p->tf);
}

static inline uint64 arch_syscall_current_arg(int n)
{
    proc_t *p = myproc();

    return arch_syscall_tf_arg(p->tf, n);
}

static inline void arch_syscall_set_current_return(uint64 value)
{
    proc_t *p = myproc();

    arch_syscall_tf_set_return(p->tf, value);
}

#endif // __ARCH_SYSCALL_H__

// 这个头文件通常认为其他.h文件都应该include
#ifndef __COMMON_H__
#define __COMMON_H__

// 类型定义

typedef char                   int8;
typedef short                  int16;
typedef int                    int32;
typedef long long              int64;
typedef unsigned char          uint8; 
typedef unsigned short         uint16;
typedef unsigned int           uint32;
typedef unsigned long long     uint64;

typedef unsigned long long         reg; 
typedef enum {false = 0, true = 1} bool;

#ifndef NULL
#define NULL ((void*)0)
#endif

// OS全局变量
#define NCPU 2
#define PGSIZE 4096    // 物理页大小
#define NPROC 64       // 最大进程数量

#define BLOCK_SIZE 512      // 磁盘的block大小 

// 辅助宏

#define MAX(a,b) ((a) > (b) ? (a) : (b)) // 取大
#define MIN(a,b) ((a) < (b) ? (a) : (b)) // 取小

#define ALIGN_UP(addr,refer) (((addr) + (refer) - 1) & ~((refer) - 1)) // 向上对齐
#define ALIGN_DOWN(addr,refer) ((addr) & ~((refer) - 1)) // 向下对齐

#endif // __COMMON_H__

// Physical memory layout

// qemu -machine virt is set up like this,
// based on qemu's hw/riscv/virt.c:
//
// 00001000 -- boot ROM, provided by qemu
// 02000000 -- CLINT
// 0C000000 -- PLICp
// 10000000 -- uart0 
// 10001000 -- virtio disk 
// 80000000 -- qemu's boot ROM loads the kernel here,
//             then jumps here.
// unused RAM after 80000000.

// the kernel uses physical memory thus:
// 80000000 -- entry.S, then kernel text and data
// end -- start of kernel page allocation area
// PHYSTOP -- end RAM used by the kernel

/* memory leyout */
#ifndef __MEMLAYOUT_H__
#define __MEMLAYOUT_H__

#include "common.h"

// 内核基地址
#define KERNEL_BASE 0x80000000ul
// 用户基地址
#define USER_BASE PGSIZE // 进程代码段起始地址

// UART 相关
#define UART_BASE  0x10000000ul
#define UART_IRQ   10

// SiFive Test (Shutdown)
#define VIRT_TEST_BASE 0x100000ul

// virtio 相关
#define VIRTIO_BASE  0x10001000ul
#define VIRTIO_IRQ   1

// platform-level interrupt controller(PLIC)
#define PLIC_BASE 0x0c000000ul
#define PLIC_SIZE 0x04000000ul
#define PLIC_PRIORITY(id) (PLIC_BASE + (id) * 4)
#define PLIC_PENDING (PLIC_BASE + 0x1000)
#define PLIC_MENABLE(hart) (PLIC_BASE + 0x2000 + (hart)*0x100)
#define PLIC_SENABLE(hart) (PLIC_BASE + 0x2080 + (hart)*0x100)
#define PLIC_MPRIORITY(hart) (PLIC_BASE + 0x200000 + (hart)*0x2000)
#define PLIC_SPRIORITY(hart) (PLIC_BASE + 0x201000 + (hart)*0x2000)
#define PLIC_MCLAIM(hart) (PLIC_BASE + 0x200004 + (hart)*0x2000)
#define PLIC_SCLAIM(hart) (PLIC_BASE + 0x201004 + (hart)*0x2000)

// core local interruptor(CLINT)
#define CLINT_BASE 0x2000000ul
#define CLINT_SIZE 0xa000000ul
#define CLINT_MSIP(hartid) (CLINT_BASE + 4 * (hartid))
#define CLINT_MTIMECMP(hartid) (CLINT_BASE + 0x4000 + 8 * (hartid))
#define CLINT_MTIME (CLINT_BASE + 0xBFF8)

// 定义一个相当大的VA, 规定所有VA不得大于它
#define VA_MAX (1ul << 38)

// 定义用户态和内核态切换用到的代码所在的虚拟地址(用户和内核页表都使用)
#define TRAMPOLINE (VA_MAX - PGSIZE)

// 定义用户态和内核态切换用到的数据所在的虚拟地址(仅用户页表使用)
#define TRAPFRAME (TRAMPOLINE - PGSIZE)

// 每个进程内核栈的页数与 guard 页布局。
// VFS + ext4/fat32 多层调用链 + 路径解析较深,单页(4KB)会溢出写入 guard
// 页触发 store 缺页 panic,故内核栈用 2 页(8KB),其下再留 1 个 guard 页。
#define KSTACK_PAGES 2
#define KSTACK_GUARD 1
#define KSTACK_STRIDE (KSTACK_PAGES + KSTACK_GUARD)

// 定义各个进程的内核栈的虚拟地址(间隔分布,含 guard 页)
#define KSTACK(id) (TRAPFRAME - ((id) + 1) * KSTACK_STRIDE * PGSIZE)

// 用户地址空间的mmap区域位于stack和heap之间
// 目前限定它占32MB(8096个page) [MMAP_BEGIN, MMAP_END)

// 用户栈顶。必须低于所有内核 KSTACK 虚拟区(含最低栈的 guard 页),避免重叠。
#define USER_STACK_TOP (TRAPFRAME - (KSTACK_STRIDE * NPROC + 1) * PGSIZE)

// 映射区域的终点(给 ustack 留 32 个 page 的空间)
#define MMAP_END  (USER_STACK_TOP - 32 * PGSIZE)

// 映射区域的起点
#define MMAP_BEGIN  (MMAP_END - 8096 * PGSIZE)
#endif

#include "arch/cpu.h"
#include "arch/intr.h"
#include "lib/print.h"
#include "lib/str.h"
#include "mem/pmem.h"
#include "mem/vmem.h"
#include "trap/trap.h"
#include "dev/timer.h"
#include "dev/uart.h"
#include "proc/proc.h"
#include "dev/vio.h"
#include "fs/file.h"
#include "dev/sbi.h"
#include "fs/mount.h"

volatile static int started = 0;

int main()
{
    int cpuid = arch_cpu_id();

    if(cpuid == 0) {

        sbi_console_putchar('S');
        sbi_console_putchar('B');
        sbi_console_putchar('I');
        sbi_console_putchar('\n');

        // uart_init();
        print_init();
        printf("cpu %d is booting!\n", cpuid);
        pmem_init();
        printf("pmem_init done\n");
        kvm_init();
        printf("kvm_init done\n");
        kvm_inithart();
        printf("kvm_inithart done\n");
        trap_kernel_init();
        printf("trap_kernel_init done\n");
        trap_kernel_inithart();
        printf("trap_kernel_inithart done\n");
        mmap_init();
        printf("mmap_init done\n");
        virtio_disk_init();
        printf("virtio_disk_init done\n");
        proc_init();
        printf("proc_init done\n");
        file_init();
        printf("file_init done\n");
        mount_init();
        printf("mount_init done\n");
        timer_create();
        timer_init(); // S-mode timer init
        printf("timer_init done\n");
        arch_intr_on();
        printf("intr_on done\n");

        proc_make_first();
        printf("proc_make_first done\n");

        __sync_synchronize();
        // started = 1;

    } else {

        while(started == 0);

        __sync_synchronize();
        printf("cpu %d is booting!\n", cpuid);

        kvm_inithart();
        trap_kernel_inithart();
        arch_intr_on();
    }
    proc_scheduler();

    while (1);    
}

/**
 * @file boot.c
 * @brief LoongArch64 C boot path for the shared first process.
 *
 * This boot path initializes the platform, shared kernel services, the first
 * process, and then enters the shared scheduler.
 */

#include "platform/platform.h"
#include "platform/boot_info.h"
#include "platform/cpu.h"
#include "platform/irq.h"
#include "fs/light_runtime.h"
#include "fs/runtime_hooks.h"
#include "fs/file.h"
#include "fs/mount.h"
#include "mm/layout.h"
#include "mm/memory_discovery.h"
#include "mm/memory_map.h"
#include "mem/mmap.h"
#include "mm/pmem_boot.h"
#include "proc/boot_shared.h"
#include "proc/proc.h"
#include "storage/virtio_pci_block.h"

/**
 * @brief Write one byte to the LoongArch QEMU UART.
 *
 * The early baseline uses polling against the 16550 line-status register. This
 * keeps the first boot path independent of interrupts and locks.
